class IndentationRuleReproTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `issue 945 - parenthesis unexpectedly indented in expression but not in if`() {
        val code =
            """
            val pass = if (condition1) {
                (
                    condition2
                )
            } else {
                condition3
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }

    @Test
    fun `issue 945 - parenthesis unexpectedly indented in expression but not in if - multiple lines condition`() {
        val code =
            """
            val pass = if (
                condition1
            ) {
                (
                    condition2
                )
            } else {
                condition3
            }
            """.trimIndent()
        indentationRuleAssertThat(code)
            .withEditorConfigOverride(CODE_STYLE_PROPERTY to ktlint_official)
            .hasNoLintViolations()
    }
}
